custom_css:
:root {
  --mario-red: #E60012;      
  --mario-green: #00A86B;    
  --mario-yellow: #FFD100;   
  --mario-brick: #B35A2B;    
  --mario-black: #000000;    
  --mario-white: #FFFFFF;    
  --mario-blue: #0050B3;     
  --ui-color-main: #F8F0E0;  
  --ui-color-sec: #E0C890;   
  --top-bar-color: #E60012;  
  --chat-background-color: #F8F4E8;
  --chat-bg-pattern: linear-gradient(rgba(0, 80, 179, 0.08) 1px, transparent 1px),
                     linear-gradient(90deg, rgba(0, 80, 179, 0.08) 1px, transparent 1px);
  --text-color-main: #3A2E2F;
  --text-color-sec: #8B4513;
  --user-color: #F0FFF0;     
  --char-color: #FFF8E0;     
  --code-color: #D4B886;     
  --gradient-mario: linear-gradient(135deg, #E52521 30%, #FEDC56 50%, #4AA02C 70%);
  --gradient-mario-horizontal: linear-gradient(90deg, #E52521 0%, #FEDC56 50%, #4AA02C 100%);

  --pixel-border: 5px solid var(--mario-black); 
  --gold-dashed-border: 2px dashed var(--mario-yellow); 
  --red-dashed-border: 3px dashed var(--mario-red); 

  --pixel-shadow: 6px 6px 0px var(--mario-black); 
  --pixel-inner-shadow: inset 4px 4px 0 rgba(0,0,0,0.3); 
  --drawer-bg: var(--ui-color-sec); 
  --drawer-content-bg: var(--ui-color-main); 

  --mes-width: 100%;
  --mes-block-width: 100%;
  --box-border-radius: 0px;
  --border-radius-small: 0px;
  --border-radius-medium: 0px;
  --top-distance: 0px;
  --bottom-distance: 0px;
  --chat-send-spacing: 0px;
  --leftRight-chat-spacing: 0px;
  --scroll-width: 12px;
  --spacing-long: 8px;
  --spacing-short: 4px;
  --icon-size: var(--mainFontSize);
  --topBarIconSize: calc(var(--icon-size) * 2);

  --chat-safety-padding: 40px;
}

/* --- 新增动画 --- */
@keyframes mario-jump {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-14px); }
}

@keyframes star-twinkle {
  0%, 100% { opacity: 0.8; transform: rotate(0deg) scale(1); }
  50% { opacity: 1; transform: rotate(180deg) scale(1.25); }
}

@keyframes power-up {
  0% { filter: hue-rotate(0deg) brightness(1); }
  100% { filter: hue-rotate(360deg) brightness(1.7); }
}

/* --- 原有动画微调增强 --- */
@keyframes pixel-bounce {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(0.86); }
}

@keyframes smooth-expand {
  0% { transform: scaleY(0); opacity: 0; transform-origin: bottom; }
  100% { transform: scaleY(1); opacity: 1; transform-origin: bottom; }
}

@keyframes float-avatar {
  0% { transform: translateY(0px); }
  50% { transform: translateY(-10px); }
  100% { transform: translateY(0px); }
}

@keyframes pulse-border {
  0% { outline-color: var(--mario-yellow); box-shadow: var(--pixel-shadow), inset 0 0 0 0px var(--mario-yellow); }
  50% { outline-color: var(--mario-red); box-shadow: var(--pixel-shadow), inset 0 0 0 4px var(--mario-red); }
  100% { outline-color: var(--mario-yellow); box-shadow: var(--pixel-shadow), inset 0 0 0 0px var(--mario-yellow); }
}

@keyframes slide-in-bottom {
  from { transform: translateY(45px); opacity: 0; }
  to { transform: translateY(0); opacity: 1; }
}

@keyframes pop-in {
  0% { transform: scale(0.35); opacity: 0; }
  70% { transform: scale(1.18); opacity: 1; }
  100% { transform: scale(1); opacity: 1; }
}

@keyframes coin-glint {
  0%, 100% { filter: brightness(1) contrast(1); }
  50% { filter: brightness(1.7) contrast(1.35); }
}

@keyframes brick-hit {
  0% { transform: translateY(0); }
  25% { transform: translateY(-8px); }
  50% { transform: translateY(0); }
  75% { transform: translateY(-4px); }
  100% { transform: translateY(0); }
}

@keyframes text-pop {
  from { clip-path: inset(0 100% 0 0); }
  to { clip-path: inset(0 0 0 0); }
}

/* --- 全局样式增强 --- */
*:not(i, .fa-solid, .fa-fw, icon) {
  font-family: 'Press Start 2P', 'Pixelify Sans', monospace !important;
  letter-spacing: 0.045em;
  -webkit-font-smoothing: none;
  font-smooth: never;
  text-rendering: optimizeSpeed;
}

::selection {
  background: var(--mario-red);
  color: var(--mario-white);
  text-shadow: 3px 3px 0 var(--mario-black);
}

/* --- 表单元素进一步增强 --- */
input[type="checkbox"] {
  width: 22px;
  height: 22px;
  border: var(--pixel-border) !important;
  outline: var(--gold-dashed-border);
  outline-offset: 3px;
  box-shadow: var(--pixel-inner-shadow);
  background: var(--mario-white);
  position: relative;
  appearance: none;
  cursor: pointer;
  transition: all 0.35s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

input[type="checkbox"]:checked {
  background: var(--mario-green);
  animation: brick-hit 0.45s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  transform: scale(1.1);
}

input[type="checkbox"]:checked::before {
  content: "✓";
  position: absolute;
  top: -4px;
  left: 3px;
  color: var(--mario-white);
  font-size: 15px;
  text-shadow: 2px 2px 0 var(--mario-black);
}

input[type="radio"] {
  width: 22px;
  height: 22px;
  border: var(--pixel-border) !important;
  outline: var(--gold-dashed-border);
  outline-offset: 3px;
  background: var(--mario-white);
  appearance: none;
  cursor: pointer;
  border-radius: 0 !important; 
  box-shadow: var(--pixel-inner-shadow);
  transition: all 0.35s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

input[type="radio"]:checked {
  background: var(--mario-red);
  box-shadow: inset 0 0 0 6px var(--mario-white); 
  animation: pixel-bounce 0.45s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  transform: scale(1.1);
}

input[type=range]::-webkit-slider-thumb {
  height: 30px;
  width: 16px;
  background: var(--mario-yellow);
  border: 4px solid var(--mario-black);
  box-shadow: 4px 4px 0 rgba(0,0,0,0.6);
  animation: coin-glint 1.8s infinite ease-in-out;
}

input[type=range]:focus::-webkit-slider-thumb {
  background: var(--mario-white);
  transform: scale(1.35);
  animation: power-up 2s infinite linear;
}

select {
  background-color: var(--ui-color-main);
  border: var(--pixel-border) !important;
  outline: var(--gold-dashed-border) !important;
  outline-offset: -5px;
  box-shadow: var(--pixel-shadow);
  transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

select:hover {
  background-color: var(--mario-white);
  transform: translateY(-3px);
  animation: mario-jump 0.7s ease-out;
}

/* --- 滚动条进一步增强 --- */
::-webkit-scrollbar {
  width: var(--scroll-width);
  height: var(--scroll-width);
  background: var(--mario-black);
  border: 4px solid var(--mario-white);
  box-shadow: var(--pixel-inner-shadow);
}

::-webkit-scrollbar-thumb {
  background: var(--gradient-mario-horizontal);
  border: 4px solid var(--mario-black);
  box-shadow: var(--pixel-inner-shadow);
  animation: coin-glint 3s infinite ease-in-out;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--mario-yellow);
  animation: power-up 1s infinite linear;
}

/* --- 设置面板头像（强制方形） --- */
.avatar:not(.mesAvatarWrapper *), 
.avatar img:not(.mesAvatarWrapper *) {
  border: 5px solid var(--mario-black) !important;
  outline: var(--gold-dashed-border);
  outline-offset: 2px;
  box-shadow: var(--pixel-shadow) !important;
  border-radius: 0px !important;
  transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

.avatar:not(.mesAvatarWrapper *):hover, 
.avatar img:not(.mesAvatarWrapper *):hover {
  transform: scale(1.15) rotate(4deg);
  animation: mario-jump 0.9s ease-out;
}

/* --- 收藏角色卡边框红色虚线（常见收藏角色类） --- */
.fav .avatar, .favorite .avatar, .char_card.fav, .char_tile.fav, .character_favorite .avatar, .fav_char .avatar {
  outline: var(--red-dashed-border) !important;
  outline-offset: 2px;
}

/* --- 标题装饰（超级蘑菇保持） --- */
.standoutHeader strong,
#right-nav-panel h2,
.drawer-content > h3,
.drawer-content .flex-container h3:first-of-type:not(#Backgrounds .textAlignCenter),
.drawer-content .flex-container .flex-container h3:first-of-type,
.popup h3:not(dialog *),
.short_settings_block h3 {
  font-size: calc(var(--mainFontSize) * 1.2);
  font-weight: 400;
  color: var(--text-color-main);
  letter-spacing: 0.13em;
  line-height: 2.5;
  text-shadow: 2px 2px 0px #E0C890, 4px 4px 0px rgba(179, 90, 43, 0.35); 
  border-bottom: var(--gold-dashed-border);
}

.standoutHeader strong::before,
#right-nav-panel h2::before,
.drawer-content > h3::before,
.drawer-content .flex-container h3:first-of-type:not(#Backgrounds .textAlignCenter)::before,
.drawer-content .flex-container .flex-container h3:first-of-type::before,
.popup h3:not(dialog *)::before,
.short_settings_block h3::before {
  content: "";
  display: inline-block;
  width: 22px;
  height: 22px;
  background: 
    radial-gradient(circle at 50% 30%, white 2px, var(--mario-red) 3px, var(--mario-red) 7px, transparent 7px),
    radial-gradient(circle at 30% 60%, white 2px, transparent 2px),
    radial-gradient(circle at 70% 60%, white 2px, transparent 2px),
    linear-gradient(to bottom, var(--mario-red) 65%, var(--mario-green) 65%);
  border: 3px solid var(--mario-black);
  border-radius: 50% 50% 40% 40% / 60% 60% 40% 40%;
  margin-right: 12px;
  vertical-align: middle;
  box-shadow: 3px 3px 0 rgba(0,0,0,0.4);
  animation: float-avatar 2.5s infinite ease-in-out;
}

/* --- 分隔线 --- */
.standoutHeader:not(h4),
#rm_PinAndTabs,
#top-settings-holder .drawer:not(:first-child):not(:last-child) .drawer-content .alignItemsBaseline.wide100p,
#rm_api_block .flex-container.alignItemsBaseline,
#title_api,
#AdvancedFormatting .flex-container.alignItemsBaseline:not(h3),
#WorldInfo .alignitemscenter:not(#world_popup *),
#user-settings-block div[name="userSettingsRowOne"],
#rm_extensions_block .alignitemscenter.flex-container.wide100p:not(.justifyCenter) {
  border-bottom: 5px solid var(--mario-brick);
  outline: var(--gold-dashed-border);
  padding-bottom: calc(var(--mainFontSize) * 0.35);
  margin-bottom: calc(var(--mainFontSize) * 0.7);
}

/* --- 抽屉与面板（减少虚线使用，仅在打开/选中时用红色虚线） --- */
.drawer { 
  background: var(--drawer-bg) !important; 
  border-right: 5px solid var(--mario-brick); 
  outline: none; /* 移除默认虚线 */
  box-shadow: var(--pixel-shadow);
}

.drawer-content { 
  background: var(--drawer-content-bg) !important; 
  padding: var(--spacing-long); 
  border: var(--gold-dashed-border);
  animation: slide-in-bottom 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275); 
}

.inline-drawer-header,
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#top-settings-holder h4:not(#ai-config-button *):not(#rightNavHolder *) {
  border-left: 7px solid var(--mario-red);
  border-top: var(--gold-dashed-border);
  border-bottom: var(--gold-dashed-border);
  padding-left: calc(var(--spacing-long) + 6px);
  background: var(--ui-color-sec);
  color: var(--text-color-sec);
  transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

.inline-drawer-header:hover {
  background: var(--mario-yellow);
  color: var(--mario-black);
  transform: translateX(8px);
  animation: brick-hit 0.45s ease-out;
}

/* 角色选择器相关（抽屉图标）虚线优化：默认金色细虚线，打开/选中时红色虚线 */
.drawer-icon {
  background: var(--mario-yellow) !important;
  border: var(--pixel-border) !important;
  outline: var(--gold-dashed-border) !important; /* 默认细金色虚线 */
  outline-offset: -2px;
  box-shadow: var(--pixel-inner-shadow);
  transition: all 0.25s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  opacity: 1 !important;
  width: var(--topBarIconSize) !important;
  height: var(--topBarIconSize) !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  padding: 0 !important;
  box-sizing: border-box;
}

.drawer-icon:hover { 
  transform: translateY(-5px) scale(1.1); 
  background: var(--mario-white) !important; 
  outline: var(--gold-dashed-border) !important;
}

.drawer-icon.openIcon { 
  transform: translateY(-5px) scale(1.1); 
  background: var(--mario-white) !important; 
  outline: var(--red-dashed-border) !important; /* 选中/打开时红色虚线 */
  outline-offset: -2px;
}

.drawer-icon i { 
  filter: drop-shadow(2px 2px 0px rgba(0,0,0,0.5)); 
}

/* --- 输入区域（focus时红色虚线） --- */
input[type="text"], input[type="number"], input[type="password"], input[type="search"], textarea:not([type="search"]), .text_pole:not(.objective-task) {
  background: var(--ui-color-main);
  border: var(--pixel-border) !important;
  outline: var(--gold-dashed-border) !important;
  outline-offset: -8px;
  box-shadow: var(--pixel-shadow), var(--pixel-inner-shadow);
  color: var(--text-color-main);
  transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

input::placeholder, textarea::placeholder {
  color: rgba(58, 46, 47, 0.65);
}

input:focus, textarea:focus, .text_pole:focus {
  background: var(--mario-white);
  transform: translateY(-4px) scale(1.03);
  outline: var(--red-dashed-border) !important;
  outline-offset: -8px;
  animation: pulse-border 2s infinite ease-in-out;
}

/* --- 顶部工具栏（原始） --- */
#top-bar {
  background: var(--gradient-mario) !important;
  border-bottom: var(--pixel-border);
  border-top: var(--gold-dashed-border);
  box-shadow: 0 4px 0px var(--mario-black);
  animation: coin-glint 4s infinite ease-in-out;
}

/* --- 按钮 --- */
.menu_button:not(.mes_edit_buttons *) {
  background: var(--gradient-mario) !important;
  border: var(--pixel-border) !important;
  outline: var(--gold-dashed-border);
  outline-offset: -8px;
  color: var(--mario-white) !important;
  box-shadow: var(--pixel-inner-shadow), 7px 7px 0px rgba(0,0,0,0.35);
  text-shadow: 3px 3px 0px var(--mario-black);
  transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

.menu_button:hover:not(.mes_edit_buttons *) {
  filter: brightness(1.25) contrast(1.2);
  animation: brick-hit 0.45s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

.menu_button:active:not(.mes_edit_buttons *) {
  transform: translateY(10px); 
  box-shadow: 0px 0px 0 var(--mario-black), inset 4px 4px 0 rgba(0,0,0,0.6);
}

.redWarningBG, .red_button, #delete_button, #send_button {
  background: var(--mario-red) !important;
  border: var(--pixel-border) !important;
  outline: var(--gold-dashed-border);
  outline-offset: -8px;
  box-shadow: 5px 5px 0 var(--mario-black), inset -4px -4px 0 #990000, inset 4px 4px 0 #ff6666 !important;
}

.redWarningBG:active, .red_button:active, #send_button:active {
  transform: translateY(8px) !important;
  box-shadow: 2px 2px 0 var(--mario-black), inset 4px 4px 0 #990000, inset -4px -4px 0 #ff6666 !important;
}

#send_button:hover {
  filter: brightness(1.3);
  animation: power-up 1s infinite linear;
}

/* --- 聊天区域 --- */
#chat {
  background-color: var(--chat-background-color);
  background-image: var(--chat-bg-pattern);
  background-size: 16px 16px;
  padding-left: 0 !important;
  padding-right: 0 !important;
}

/* --- 消息气泡（边距最小化） --- */
.mes {
  width: 100% !important;
  display: flex !important;
  flex-direction: column;
  border: var(--pixel-border) !important;
  outline: var(--gold-dashed-border);
  outline-offset: -8px;
  background-color: var(--ui-color-main) !important;
  margin: 20px 0 6px 0 !important; 
  padding: 0px !important;         
  box-shadow: var(--pixel-shadow);
  position: relative;
  box-sizing: border-box;
  animation: slide-in-bottom 0.55s cubic-bezier(0.175, 0.885, 0.32, 1.275); 
  transition: all 0.45s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

/* --- 聊天正文（边距最小化） --- */
.mes_text {
  padding: 6px 10px !important;    
  margin: 0 !important;
  line-height: 1.6;
  animation: text-pop 0.7s ease-out; 
}

/* --- 引用文本（保持原始细致风格） --- */
.mes_text q {
  display: inline;
  border-radius: 0 !important;
  padding: 1px 4px !important;
  margin: 2px 2px 2px 0;
  -webkit-box-decoration-break: clone;
  box-decoration-break: clone;
  line-height: 1.5;
  box-shadow: 1px 1px 0 rgba(0,0,0,0.3);
  border: 1px solid var(--mario-black);
  outline: 1px dashed var(--mario-yellow);
  transition: transform 0.25s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

div[is_user="false"] .mes_text q {
  background-color: var(--mario-red) !important;
  color: var(--mario-white) !important;
}

div[is_user="true"] .mes_text q {
  background-color: var(--mario-green) !important;
  color: var(--mario-white) !important;
}

.mes_text q:hover {
  transform: scale(1.05);
}

/* --- Markdown 其他部分继续增强 --- */
.mes_text strong {
  color: var(--mario-red);
  text-shadow: 2px 2px 0 var(--mario-yellow);
  animation: star-twinkle 3s infinite ease-in-out;
  font-weight: bold;
}

.mes_text em {
  color: var(--mario-blue);
  font-style: normal;
  border-bottom: 4px solid var(--mario-blue);
  padding-bottom: 3px;
}

.mes_text blockquote {
  background: var(--ui-color-sec) !important;
  border: 4px solid var(--mario-brick) !important;
  padding: 16px !important;
  margin: 14px 0 !important;
  position: relative;
  box-shadow: 6px 6px 0 var(--mario-black);
}

.mes_text blockquote::before {
  content: "!";
  position: absolute;
  left: -14px;
  top: -14px;
  background: var(--mario-yellow);
  width: 28px;
  height: 28px;
  border: 4px solid var(--mario-black);
  text-align: center;
  line-height: 28px;
  font-size: 16px;
  animation: coin-glint 2s infinite ease-in-out;
}

.mes_text table {
  border-collapse: collapse;
  width: 100%;
  border: 4px solid var(--mario-black);
  margin: 14px 0;
  box-shadow: 6px 6px 0 rgba(0,0,0,0.4);
  animation: pop-in 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

.mes_text th {
  background: var(--mario-brick);
  color: var(--mario-white);
  border: 3px solid var(--mario-black);
  padding: 10px;
  text-shadow: 2px 2px 0 var(--mario-black);
}

.mes_text td {
  border: 3px solid var(--mario-black);
  padding: 10px;
  background: rgba(255,255,255,0.7);
}

.mes_text hr {
  border: none;
  height: 10px;
  background: repeating-linear-gradient(90deg, var(--mario-brick) 0px, var(--mario-brick) 20px, transparent 20px, transparent 40px);
  margin: 24px 0;
  box-shadow: 0 5px 0 var(--mario-black);
}

.mes_text a {
  color: var(--mario-blue);
  text-decoration: none;
  border-bottom: 3px dotted var(--mario-red);
  transition: all 0.35s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

.mes_text a:hover {
  background: var(--mario-yellow);
  color: var(--mario-black);
  border-bottom-style: solid;
  transform: scale(1.1);
}

.mes_text img {
  border: 6px solid var(--mario-black);
  outline: 6px solid var(--mario-white);
  box-shadow: 8px 8px 0 rgba(0,0,0,0.4);
  margin: 14px 0;
  max-width: 100%;
  transition: transform 0.4s ease;
}

.mes_text img:hover {
  transform: scale(1.06);
  animation: mario-jump 0.7s ease-out;
}

/* --- 编辑文本框 --- */
.mes_edit_textarea {
  background: var(--mario-black) !important;
  color: #00FF00 !important;
  font-family: monospace !important;
  border: 5px solid var(--mario-yellow) !important;
  padding: 14px;
  box-shadow: inset 5px 5px 0 rgba(0,0,0,0.6);
}

/* --- 头像（强制方形） --- */
.mesAvatarWrapper { 
  position: absolute; 
  top: -40px; 
  z-index: 100; 
  transition: transform 0.45s cubic-bezier(0.175, 0.885, 0.32, 1.275); 
}

.avatar, .avatar img { 
  border-radius: 0px !important; 
} 

div[is_user="false"] .mesAvatarWrapper { left: 5px; }
div[is_user="false"] .avatar img { 
  border: 6px solid var(--mario-red) !important; 
  outline: var(--gold-dashed-border);
  box-shadow: 7px 7px 0 var(--mario-black); 
}

div[is_user="false"] .avatar img:hover {
  animation: mario-jump 1.4s ease-in-out infinite;
}

div[is_user="true"] .mesAvatarWrapper { right: 5px; left: auto; }
div[is_user="true"] .avatar img { 
  border: 6px solid var(--mario-blue) !important; 
  outline: var(--gold-dashed-border);
  box-shadow: -7px 7px 0 var(--mario-black); 
}

div[is_user="true"] .avatar img:hover {
  animation: mario-jump 1.4s ease-in-out infinite;
}

/* --- 名字标签（适应最小边距） --- */
.mes_block .ch_name {
  opacity: 0; 
  position: absolute;
  top: -35px; 
  padding: 4px 8px;
  background: rgba(58, 46, 47, 0.98) !important; 
  color: var(--mario-yellow) !important;      
  text-shadow: 3px 3px 0px var(--mario-black); 
  border: 3px solid var(--mario-black);
  outline: 2px dashed var(--mario-yellow);     
  outline-offset: -5px;
  font-size: calc(var(--mainFontSize) * 0.75);
  display: flex;
  align-items: center;
  gap: 10px;                  
  z-index: 120;               
  white-space: nowrap;        
  transition: all 0.45s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

.mes:hover .ch_name { 
  opacity: 1; 
  animation: smooth-expand 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; 
}

div[is_user="false"] .ch_name { left: 55px; }
div[is_user="true"] .ch_name { right: 55px; flex-direction: row-reverse; }

/* --- 发送栏 --- */
#send_form {
  background: var(--mario-green) !important;
  border-top: 10px solid #007000 !important;
  outline: var(--gold-dashed-border);
  outline-offset: -14px;
  padding: 14px 7px;
  box-shadow: 0 -8px 0 var(--mario-black);
}

#send_form textarea {
  background: var(--mario-black) !important;
  color: #00FF00 !important;
  border: 5px solid #007000 !important;
  outline: 3px dashed var(--mario-yellow) !important;
  box-shadow: inset 5px 5px 0 rgba(0,0,0,0.6);
}

/* --- 代码块 --- */
code, .hljs {
  background: var(--code-color);
  border: 5px solid var(--mario-brick);
  outline: var(--gold-dashed-border);
  outline-offset: -7px;
  color: #2c2121;
  padding: 10px;
  box-shadow: var(--pixel-inner-shadow);
}

code:hover {
  transform: scale(1.03);
  animation: coin-glint 2s infinite ease-in-out;
}

/* --- 提示与弹出层 --- */
#toast-container > div {
  opacity: 1 !important;
  box-shadow: var(--pixel-shadow) !important;
  border: var(--pixel-border) !important;
  border-radius: 0 !important;
  padding: 14px 14px 14px 50px !important;
  animation: pop-in 0.55s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards; 
}

.popup {
  background: var(--ui-color-main) !important;
  border: var(--pixel-border) !important;
  box-shadow: var(--pixel-shadow) !important;
  animation: pop-in 0.55s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards;
}

/* --- 响应式 --- */
@media screen and (max-width: 1000px) {
  .mes { 
    margin-top: 30px !important; 
    width: 100% !important; 
  }
  .mesAvatarWrapper { top: -40px; }
  .ch_name { font-size: calc(var(--mainFontSize) * 0.7); }
}
